import './style/index.less'
import './components/index.less'
import { useCallback, useEffect, useMemo, useRef, useState } from 'react'
import { useTranslation } from 'react-i18next'
import { useLocation, useNavigate, useParams } from 'react-router-dom'
import { Button, Form, Message, Space } from '@arco-design/web-react'
import type { FormInstance, TableColumnProps } from '@arco-design/web-react'
import { IconEye, IconPlus } from '@arco-design/web-react/icon'
import type {
  RequestOptions,
  UploadItem,
} from '@arco-design/web-react/es/Upload/interface'
import { useRequest } from 'ahooks'
import FullScreenTableSection from '@common/components/FullScreenTableSection'
import ListFilterHseForm from '@common/components/ListFilterHseForm'
import PageWrapper from '@common/components/PageWrapper'
import UnifiedTableStyle from '@common/components/UnifiedTableStyle'
import { File_UPLOAD_TYPE } from '@common/constants/uploadTypes'
import { uploadFile } from '@common/service/apis/file'
import { getLanguage } from '@common/utils/localStorage'
import ActivationDetailSection from './components/ActivationDetailSection'
import ActivationFormSection from './components/ActivationFormSection'
import StepCompleteModal, {
  type ModalType,
  type StepCompletePayload,
} from './components/StepCompleteModal'
import { LanguageEnum } from '@common/constants/language'
import { renderEllipsisText } from '@common/components/EllipsisText'
import { handelFieldNameShow } from '@/utils/tools.ts'
import {
  ACTIVATION_ACTIVITY_CODE,
  ACTIVATION_STEP,
  DEFAULT_EMPTY_NUM,
  DEFAULT_MIN_ID,
  DEFAULT_PAGE_SIZE,
  EMERGENCY_LOCATION,
  EMERGENCY_TYPE_META,
  NEED_EVACUATION,
  TEAM_ROLE_LABEL_MAP,
  TEAM_VEST_COLOR,
} from './constants'
import {
  completeResponseActivationStageRequest,
  getResponseActivationActivePageRequest,
  getResponseActivationDetailRequest,
  getResponseActivationHistoryPageRequest,
  getResponseActivationPlanOptionsRequest,
  getResponseActivationSeverityOptionsRequest,
  getResponseActivationTeamOptionsRequest,
  getTeamDetailRequest,
  getTeamInfoRequestByPlanId,
  saveResponseActivationRequest,
} from '@/service'
import type {
  PageMode,
  ListTab,
  DetailLoadingMap,
  OptionItem,
  SeverityOption,
  TeamOptionDto,
  PlanOptionDto,
  ActivationListItemDto,
  ActivationDetailDto,
  ScenarioRecord,
  EmergencyTeam,
  TeamMemberDto,
  TimelineStepDetail,
  DetailState,
  ActivationRecord,
  ActivationFormValues,
  PageRes,
} from '@/types/emergencyResponse'

const ACTIVATION_LIST_PATH = '/emergency-response/emergency-response-activation'
const ACTIVATION_CREATE_PATH = `${ACTIVATION_LIST_PATH}/activate`
// TODO(联调): 待 Incident Report 模块改造后替换为真实详情路由
const INCIDENT_REPORT_DETAIL_PATH =
  '/incident-report/incident-report-management/list'
const getActivationDetailPath = (id: string, sourceTab: ListTab) =>
  `${ACTIVATION_LIST_PATH}/detail/${id}/${sourceTab}`
const toOptionalText = (value?: string) => {
  return value ? value : undefined
}

const toNumberOrUndefined = (value: unknown): number | undefined => {
  if (value === undefined || value === null || value === '') return undefined
  const result = Number(value)
  return Number.isFinite(result) ? result : undefined
}

const toVestColorName = (vestColor?: number): 'orange' | 'yellow' | 'green' => {
  if (vestColor === TEAM_VEST_COLOR.YELLOW) return 'yellow'
  if (vestColor === TEAM_VEST_COLOR.GREEN) return 'green'
  return 'orange'
}

const toRoleName = (roleCode?: number) => {
  return TEAM_ROLE_LABEL_MAP[roleCode || DEFAULT_EMPTY_NUM] || '-'
}

const normalizeFloorCodes = (floorCodes?: string | string[]) => {
  if (Array.isArray(floorCodes)) {
    return floorCodes.map(String).filter(Boolean)
  }

  return String(floorCodes || '')
    .split(',')
    .map((item) => item.trim())
    .filter(Boolean)
}

const toDurationText = (
  day = DEFAULT_EMPTY_NUM,
  hour = DEFAULT_EMPTY_NUM,
  minute = DEFAULT_EMPTY_NUM,
) => `${day}d${hour}h${minute}m`

const fromTotalMinutesToText = (totalMinutes?: number) => {
  if (!totalMinutes && totalMinutes !== DEFAULT_EMPTY_NUM) return undefined
  const day = Math.floor(totalMinutes / (24 * 60))
  const hour = Math.floor((totalMinutes % (24 * 60)) / 60)
  const minute = totalMinutes % 60
  return toDurationText(day, hour, minute)
}

type ActivationStatusTone =
  | 'open'
  | 'in-progress'
  | 'contained'
  | 'recovered'
  | 'closed'

const getActivationStatusTone = (
  currentStep?: number,
  currentStepName?: string,
): ActivationStatusTone => {
  if (currentStep === ACTIVATION_STEP.ACTIVATED) return 'open'
  if (currentStep === ACTIVATION_STEP.IN_PROGRESS) return 'in-progress'
  if (currentStep === ACTIVATION_STEP.CONTAINED) return 'contained'
  if (currentStep === ACTIVATION_STEP.RECOVERED) return 'recovered'
  if (currentStep === ACTIVATION_STEP.CLOSED) return 'closed'

  const normalizedName = String(currentStepName || '')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, ' ')

  if (normalizedName.includes('open')) return 'open'
  if (normalizedName.includes('progress')) return 'in-progress'
  if (normalizedName.includes('contain')) return 'contained'
  if (normalizedName.includes('recover')) return 'recovered'
  return 'closed'
}

const getStepFromActivityCode = (activityCode?: number) => {
  if (activityCode === ACTIVATION_ACTIVITY_CODE.ACTIVATED)
    return ACTIVATION_STEP.ACTIVATED
  if (activityCode === ACTIVATION_ACTIVITY_CODE.IN_PROGRESS)
    return ACTIVATION_STEP.IN_PROGRESS
  if (activityCode === ACTIVATION_ACTIVITY_CODE.CONTAINED)
    return ACTIVATION_STEP.CONTAINED
  if (activityCode === ACTIVATION_ACTIVITY_CODE.RECOVERED)
    return ACTIVATION_STEP.RECOVERED
  if (activityCode === ACTIVATION_ACTIVITY_CODE.CLOSED)
    return ACTIVATION_STEP.CLOSED
  return DEFAULT_EMPTY_NUM
}

const getNextStageActivityCode = (currentStep: number) => {
  if (currentStep < ACTIVATION_STEP.CONTAINED) {
    return ACTIVATION_ACTIVITY_CODE.CONTAINED
  }

  return currentStep + DEFAULT_MIN_ID
}

const toTeam = (item: TeamOptionDto): EmergencyTeam => {
  const floorCodes = normalizeFloorCodes(item.floorCodes)

  return {
    id: String(item.teamId ?? ''),
    teamNameAr: item.teamNameAr || '',
    teamNameEn: item.teamNameEn || '',
    teamObjectiveAr: item.teamObjectiveAr || '',
    teamObjectiveEn: item.teamObjectiveEn || '',
    activationCriteriaAr: item.activationCriteriaAr || '',
    activationCriteriaEn: item.activationCriteriaEn || '',
    responsibleFloor: floorCodes.length ? floorCodes.join(', ') : '-',
    responsibleFloorList: floorCodes,
    members: [],
  }
}

const toDetailState = (detail?: ActivationDetailDto): DetailState => {
  const stepDetails: Record<number, TimelineStepDetail> = {}

  if (detail?.activatedBy || detail?.activatedTime || detail?.activatedByUser) {
    stepDetails[ACTIVATION_STEP.ACTIVATED] = {
      updatedBy: detail.activatedBy,
      updatedByUser: detail.activatedByUser,
      time: detail.activatedTime,
    }
  }

  ;(detail?.activityList || []).forEach((item) => {
    const step = getStepFromActivityCode(item.activityCode)
    if (step <= ACTIVATION_STEP.ACTIVATED || step > ACTIVATION_STEP.CLOSED)
      return

    stepDetails[step] = {
      updatedBy: step < ACTIVATION_STEP.CLOSED ? item.completedBy : undefined,
      updatedByUser:
        step < ACTIVATION_STEP.CLOSED ? item.completedByUser : undefined,
      closedBy: step === ACTIVATION_STEP.CLOSED ? item.completedBy : undefined,
      closedByUser:
        step === ACTIVATION_STEP.CLOSED ? item.completedByUser : undefined,
      duration: toDurationText(
        Number(item.durationDay || DEFAULT_EMPTY_NUM),
        Number(item.durationHour || DEFAULT_EMPTY_NUM),
        Number(item.durationMinute || DEFAULT_EMPTY_NUM),
      ),
      note: item.noteEn || item.noteAr,
      noteAr: item.noteAr,
      noteEn: item.noteEn,
      time: item.completedTime,
      attachments: item.attachmentList || [],
    }
  })

  const currentStep = Number(detail?.currentStep || ACTIVATION_STEP.ACTIVATED)

  return {
    currentStep,
    canOperate: currentStep < ACTIVATION_STEP.CLOSED,
    completionTime: detail?.responseCompletionTime || undefined,
    totalDuration: fromTotalMinutesToText(detail?.totalDurationMinutes),
    responseSummaryAr: detail?.responseSummaryAr,
    responseSummaryEn: detail?.responseSummaryEn,
    recoverySummaryAr: detail?.recoverySummaryAr,
    recoverySummaryEn: detail?.recoverySummaryEn,
    lessonsLearnedAr: detail?.lessonLearnedAr,
    lessonsLearnedEn: detail?.lessonLearnedEn,
    stepDetails,
  }
}

const toActivationRecord = (item: ActivationListItemDto): ActivationRecord => ({
  id: String(item.id ?? ''),
  planId: item.planId,
  responseId: item.responseId,
  activationCode: item.activationCode ?? item.responseId,
  relatedIncidentId: item.relatedIncidentId,
  relatedIncidentCode: item.relatedIncidentCode ?? item.relatedIncidentId,
  relatedIncidentBizId: item.relatedIncidentBizId,
  scenarioNameAr: item.scenarioNameAr || '',
  scenarioNameEn: item.scenarioNameEn || '',
  teamNameAr: item.teamNameAr,
  teamNameEn: item.teamNameEn,
  emergencyType: toNumberOrUndefined(item.emergencyType),
  emergencyTeamId: item.teamId,
  emergencyLocation: toNumberOrUndefined(item.emergencyLocation),
  locationType: Number(
    item.locationType ??
      (Number(item.emergencyLocation) === EMERGENCY_LOCATION.ON_SITE ? 1 : 0),
  ),
  floor: item.floorCode,
  severityLevel: toNumberOrUndefined(item.severityLevel),
  currentStep: Number(item.currentStep || ACTIVATION_STEP.ACTIVATED),
  currentStepName: item.currentStepName || '',
  activatedTime: item.activatedTime,
  lastUpdatedTime: item.lastUpdateTime,
  responsibleEmergencyTeam: item.responsibleEmergencyTeam,
  needEvacuation: Number(item.needEvacuation || NEED_EVACUATION.NO),
  detailState: {
    currentStep: Number(item.currentStep || ACTIVATION_STEP.ACTIVATED),
    canOperate:
      Number(item.currentStep || ACTIVATION_STEP.ACTIVATED) <=
      ACTIVATION_STEP.RECOVERED,
    stepDetails: {},
  },
  severityOptions: [],
  triggerSource: undefined,
})

const mergeDetailIntoRecord = (
  base: ActivationRecord,
  detail: ActivationDetailDto,
): ActivationRecord => {
  const detailLevelId = toNumberOrUndefined(
    detail?.severityDetail?.levelId ?? detail?.severityLevel,
  )

  const severityOptions =
    detail?.severityDetail && detailLevelId
      ? [
          {
            ...detail.severityDetail,
            levelId: detailLevelId,
          },
        ]
      : []

  return {
    ...base,
    id: String(detail.id || base.id || ''),
    planId: detail.planId || base.planId,
    scenarioNameAr: detail.scenarioNameAr || base.scenarioNameAr,
    scenarioNameEn: detail.scenarioNameEn || base.scenarioNameEn,
    teamNameAr: detail.teamNameAr || base.teamNameAr,
    teamNameEn: detail.teamNameEn || base.teamNameEn,
    emergencyType: toNumberOrUndefined(
      detail.emergencyType ?? base.emergencyType,
    ),
    emergencyTeamId: detail.teamId ?? base.emergencyTeamId,
    emergencyLocation: toNumberOrUndefined(
      detail.emergencyLocation ??
        (typeof detail.locationType === 'number'
          ? detail.locationType === 1
            ? EMERGENCY_LOCATION.ON_SITE
            : EMERGENCY_LOCATION.OFF_SITE_VIRTUAL
          : base.emergencyLocation),
    ),
    locationType: Number(
      detail.locationType ??
        base.locationType ??
        (Number(detail.emergencyLocation ?? base.emergencyLocation) ===
        EMERGENCY_LOCATION.ON_SITE
          ? 1
          : 0),
    ),
    floor:
      detail.floors && detail.floors.length
        ? detail.floors.join(',')
        : detail.floorCode ?? base.floor,
    severityLevel:
      detailLevelId ??
      toNumberOrUndefined(detail.severityLevel ?? base.severityLevel),
    currentStep: Number(
      detail.currentStep || base.currentStep || ACTIVATION_STEP.ACTIVATED,
    ),
    currentStepName: detail.currentStepName || base.currentStepName,
    activatedTime: detail.activatedTime || base.activatedTime,
    lastUpdatedTime:
      (detail.activityList || [])[DEFAULT_EMPTY_NUM]?.completedTime ||
      base.lastUpdatedTime,
    needEvacuation: Number(
      detail?.severityDetail?.needEvacuation ??
        base.needEvacuation ??
        NEED_EVACUATION.NO,
    ),
    severityOptions,
    triggerSource: detail.triggerSource,
    activationCode:
      detail.activationCode ?? base.activationCode ?? base.responseId,
    relatedIncidentId: detail.relatedIncidentId ?? base.relatedIncidentId,
    relatedIncidentCode:
      detail.relatedIncidentCode ??
      base.relatedIncidentCode ??
      detail.relatedIncidentId ??
      base.relatedIncidentId,
    relatedIncidentStatus:
      detail.relatedIncidentStatus ?? base.relatedIncidentStatus,
    relatedIncidentBizId:
      detail.relatedIncidentBizId ?? base.relatedIncidentBizId,
    detailState: toDetailState(detail),
  }
}

const uploadActivationFile = async (option: RequestOptions) => {
  const { file, onProgress, onSuccess, onError } = option

  const config = {
    onUploadProgress: (evt: { loaded: number; total?: number }) => {
      if (!evt.total) return
      const percent = Math.round((evt.loaded * 100) / evt.total)
      onProgress(percent, undefined)
    },
  }

  const formData = new FormData()
  formData.append('file', file)
  formData.append('type', String(File_UPLOAD_TYPE.INCIDENT_REPORT))

  try {
    const res: any = await uploadFile(formData, config)
    onSuccess(res)
  } catch (e) {
    onError(e)
  }
}

const EmergencyResponseActivation = () => {
  const { t } = useTranslation(['emergencyTeams', 'common'])
  const location = useLocation()
  const navigate = useNavigate()
  const { activationId, sourceTab } = useParams<{
    activationId?: string
    sourceTab?: string
  }>()
  const tableRef = useRef<any>(null)
  const [form] = Form.useForm<ActivationFormValues>()

  // 首帧即从 URL 推导初值,避免刷新 detail 路由时先按 list 渲染、
  // 触发多余的列表请求覆盖详情数据(severityOptions 被冲为空)
  const initialActivationId = activationId ? String(activationId) : ''
  const hasValidActivationId = Boolean(initialActivationId)
  const initialMode: PageMode =
    location.pathname === ACTIVATION_CREATE_PATH
      ? 'activate'
      : hasValidActivationId
        ? 'detail'
        : 'list'

  const [mode, setMode] = useState<PageMode>(initialMode)
  const [listTab, setListTab] = useState<ListTab>('active')
  const [keyword, setKeyword] = useState('')
  const [detailRecordId, setDetailRecordId] = useState<string | null>(() =>
    initialMode === 'detail' ? initialActivationId : null,
  )
  const [detailSourceTab, setDetailSourceTab] = useState<ListTab>(() =>
    sourceTab === 'history' ? 'history' : 'active',
  )
  const [stepModalVisible, setStepModalVisible] = useState(false)

  const [selectedScenarioId, setSelectedScenarioId] = useState<string | null>(
    null,
  )
  const [selectedEmergencyType, setSelectedEmergencyType] = useState<
    number | undefined
  >()
  const [selectedTeamId, setSelectedTeamId] = useState<string | undefined>()
  const [selectedFloors, setSelectedFloors] = useState<string[]>([])
  const [selectedSeverity, setSelectedSeverity] = useState<number | null>(null)
  const [severityOptions, setSeverityOptions] = useState<SeverityOption[]>([])
  const [fileList, setFileList] = useState<UploadItem[]>([])
  const [teamRows, setTeamRows] = useState<EmergencyTeam[]>([])
  const [scenarioRows, setScenarioRows] = useState<PlanOptionDto[]>([])
  const [recordListCache, setRecordListCache] = useState<
    Record<number, ActivationRecord>
  >({})
  const recordListCacheRef = useRef<Record<number, ActivationRecord>>({})
  const [detailLoadingMap, setDetailLoadingMap] = useState<DetailLoadingMap>({})
  const resetActivationDraftState = useCallback(() => {
    setSelectedScenarioId(null)
    setSelectedEmergencyType(undefined)
    setSelectedTeamId(undefined)
    setSelectedFloors([])
    setSelectedSeverity(null)
    setSeverityOptions([])
    setFileList([])
  }, [])

  const isLanguageAR = getLanguage() === LanguageEnum.AR

  const emergencyTypeOptions = useMemo<OptionItem[]>(
    () =>
      EMERGENCY_TYPE_META.map((item) => ({
        label: t(`emergencyTeams:emergencyResponsePlan.types.${item.key}`),
        value: item.value,
      })),
    [t],
  )

  const emergencyTypeLabelMap = useMemo(
    () =>
      EMERGENCY_TYPE_META.reduce<Record<number, string>>((acc, item) => {
        acc[item.value] = t(
          `emergencyTeams:emergencyResponsePlan.types.${item.key}`,
        )
        return acc
      }, {}),
    [t],
  )

  const teamMap = useMemo(
    () =>
      teamRows.reduce<Record<number, EmergencyTeam>>((acc, item) => {
        acc[item.id] = item
        return acc
      }, {}),
    [teamRows],
  )

  const scenarioOptions = useMemo<OptionItem[]>(
    () =>
      scenarioRows
        .filter((item) =>
          selectedEmergencyType
            ? Number(item.emergencyType) === Number(selectedEmergencyType)
            : true,
        )
        .map((item) => ({
          label: isLanguageAR
            ? item.scenarioNameAr || ''
            : item.scenarioNameEn || '',
          value: item.planId,
        })),
    [isLanguageAR, scenarioRows, selectedEmergencyType],
  )

  const floorOptions = useMemo<OptionItem[]>(
    () =>
      ['G', 'M', '1', '2', '3', '4', '5', '6', 'RF', 'P1', 'P2', 'P3'].map(
        (item) => ({
          label: item,
          value: item,
        }),
      ),
    [],
  )

  const selectedScenario = useMemo<ScenarioRecord | undefined>(() => {
    if (!selectedScenarioId) return undefined
    const hit = scenarioRows.find(
      (item) => String(item.planId) === selectedScenarioId,
    )
    if (!hit) return undefined
    return {
      id: String(hit.planId),
      scenarioNameAr: hit.scenarioNameAr || '',
      scenarioNameEn: hit.scenarioNameEn || '',
      emergencyType: Number(hit.emergencyType ?? 0),
      emergencyTeamId: selectedTeamId ?? '',
      emergencyLocation: Number(form.getFieldValue('emergencyLocation') ?? 0),
      floor: selectedFloors.join(', '),
      severityLevel: selectedSeverity ?? 0,
      severityOptions,
    }
  }, [
    form,
    scenarioRows,
    selectedScenarioId,
    selectedFloors,
    selectedSeverity,
    selectedTeamId,
    severityOptions,
  ])

  const selectedTeam = useMemo(
    () => (selectedTeamId ? teamMap[selectedTeamId] : undefined),
    [selectedTeamId, teamMap],
  )

  const selectedDetailRecord = useMemo(() => {
    if (!detailRecordId) return undefined
    return recordListCache[detailRecordId]
  }, [detailRecordId, recordListCache])

  // 手动关闭已移除,推进弹窗恒为 progress 类型
  const stepModalType: ModalType = 'progress'

  const { runAsync: runActivePage } = useRequest(
    getResponseActivationActivePageRequest,
    { manual: true },
  )

  const { runAsync: runHistoryPage } = useRequest(
    getResponseActivationHistoryPageRequest,
    { manual: true },
  )

  const { runAsync: runTeamOptions } = useRequest(
    getResponseActivationTeamOptionsRequest,
    { manual: true },
  )

  const { runAsync: runTeamDetail } = useRequest(getTeamDetailRequest, {
    manual: true,
  })

  const { runAsync: runTeamInfoByPlan } = useRequest(
    getTeamInfoRequestByPlanId,
    { manual: true },
  )

  const { runAsync: runPlanOptions } = useRequest(
    getResponseActivationPlanOptionsRequest,
    { manual: true },
  )

  const { runAsync: runSeverityOptions } = useRequest(
    getResponseActivationSeverityOptionsRequest,
    {
      manual: true,
    },
  )

  const { loading: addLoading, runAsync: runAddActivation } = useRequest(
    saveResponseActivationRequest,
    { manual: true },
  )

  const { runAsync: runDetail } = useRequest(
    getResponseActivationDetailRequest,
    {
      manual: true,
    },
  )

  const { loading: stageLoading, runAsync: runCompleteStage } = useRequest(
    completeResponseActivationStageRequest,
    { manual: true },
  )

  const submitLoading = addLoading

  const setRecordById = useCallback((record: ActivationRecord) => {
    const next = {
      ...recordListCacheRef.current,
      [record.id]: record,
    }
    recordListCacheRef.current = next
    setRecordListCache(next)
  }, [])

  const setRecordDetailLoading = (id: string, loading: boolean) => {
    setDetailLoadingMap((prev) => ({ ...prev, [id]: loading }))
  }

  const loadTeamOptions = useCallback(
    async (keywordText = '') => {
      try {
        const res = (await runTeamOptions({
          keyword: keywordText || undefined,
        })) as TeamOptionDto[]

        const rows = (res || []).map((item) => toTeam(item))
        setTeamRows(rows)
        return rows
      } catch {
        setTeamRows([])
        return []
      }
    },
    [runTeamOptions],
  )

  const loadPlanOptionsByType = useCallback(
    async (emergencyType?: number) => {
      if (!emergencyType) {
        setScenarioRows([])
        return []
      }

      try {
        const res = (await runPlanOptions({
          emergencyType,
        })) as PlanOptionDto[]
        const rows = (res || []).map((item) => ({
          ...item,
          planId: String(item.planId ?? ''),
          emergencyType: Number(item.emergencyType),
        }))
        setScenarioRows(rows)
        return rows
      } catch {
        setScenarioRows([])
        return []
      }
    },
    [runPlanOptions],
  )

  const loadSeverityOptionsByPlan = useCallback(
    async (planId?: string) => {
      if (!planId) {
        setSeverityOptions([])
        setSelectedSeverity(null)
        return
      }
      try {
        const res = (await runSeverityOptions({ planId })) as SeverityOption[]
        const rows = (res || []).map((item) => ({
          ...item,
          levelId: toNumberOrUndefined(item.levelId),
          needEvacuation: Number(item.needEvacuation || NEED_EVACUATION.NO),
        }))
        const validRows = rows.filter(
          (item) => typeof item.levelId === 'number' && item.levelId > 0,
        )
        setSeverityOptions(validRows)
        setSelectedSeverity(validRows.length ? validRows[0].levelId : null)
      } catch {
        setSeverityOptions([])
        setSelectedSeverity(null)
      }
    },
    [runSeverityOptions],
  )

  // 选定 Scenario 后,基于其 Response Plan 自动带出团队与成员(责任人高亮)
  const loadTeamForScenario = useCallback(
    async (planId?: string) => {
      if (!planId) {
        setSelectedTeamId(undefined)
        return
      }
      try {
        const res = (await runTeamInfoByPlan({ planId })) as {
          emergencyTeamId?: string
          teamNameAr?: string
          teamNameEn?: string
          members?: Array<TeamMemberDto & { marked?: boolean }>
        }
        const teamId = res?.emergencyTeamId
          ? String(res.emergencyTeamId)
          : undefined
        if (!teamId) {
          setSelectedTeamId(undefined)
          return
        }
        setSelectedTeamId(teamId)

        const members = (res?.members || []).map((member, index) => ({
          key: String(member.id ?? member.userId ?? index),
          name: member.userName || '-',
          phone: member.phoneNumber || '-',
          role: toRoleName(member.roleCode),
          vestColor: toVestColorName(member.vestColor),
          isResponsible: Boolean(member.marked),
        }))

        const team: EmergencyTeam = {
          id: teamId,
          teamNameAr: res?.teamNameAr || '',
          teamNameEn: res?.teamNameEn || '',
          teamObjectiveAr: '',
          teamObjectiveEn: '',
          activationCriteriaAr: '',
          activationCriteriaEn: '',
          responsibleFloor: '-',
          responsibleFloorList: [],
          members,
        }
        setTeamRows((prev) =>
          prev.some((tm) => tm.id === teamId)
            ? prev.map((tm) => (tm.id === teamId ? team : tm))
            : [...prev, team],
        )
      } catch {
        setSelectedTeamId(undefined)
      }
    },
    [runTeamInfoByPlan],
  )

  const loadDetailById = useCallback(
    async (id: string) => {
      setRecordDetailLoading(id, true)
      try {
        const detail = (await runDetail({
          activationId: id,
        })) as ActivationDetailDto
        const base =
          recordListCacheRef.current[id] ||
          ({
            id,
            scenarioNameAr: '',
            scenarioNameEn: '',
            emergencyType: 0,
            emergencyTeamId: undefined,
            emergencyLocation: 0,
            locationType: 0,
            floor: '',
            severityLevel: 0,
            currentStep: ACTIVATION_STEP.ACTIVATED,
            currentStepName: '',
            needEvacuation: NEED_EVACUATION.NO,
            detailState: {
              currentStep: ACTIVATION_STEP.ACTIVATED,
              canOperate: ACTIVATION_STEP.ACTIVATED < ACTIVATION_STEP.CLOSED,
              stepDetails: {},
            },
            severityOptions: [],
          } as ActivationRecord)

        const merged = mergeDetailIntoRecord(base, detail)

        if (
          merged.emergencyTeamId &&
          (detail?.teamNameAr ||
            detail?.teamNameEn ||
            detail?.memberList?.length)
        ) {
          setTeamRows((prev) => {
            const target = prev.find(
              (team) => team.id === merged.emergencyTeamId,
            )
            const nextMembers = (detail.memberList || []).map(
              (member, index) => ({
                key: String(member.id || member.userId || `${index}`),
                name: member.userName || '-',
                phone: member.phoneNumber || '-',
                role: toRoleName(member.roleCode),
                vestColor: toVestColorName(member.vestColor),
                isResponsible: Boolean(member.isResponsible),
              }),
            )
            const nextTeam: EmergencyTeam = {
              id: merged.emergencyTeamId,
              teamNameAr: detail.teamNameAr || target?.teamNameAr || '',
              teamNameEn: detail.teamNameEn || target?.teamNameEn || '',
              teamObjectiveAr: target?.teamObjectiveAr || '',
              teamObjectiveEn: target?.teamObjectiveEn || '',
              activationCriteriaAr: target?.activationCriteriaAr || '',
              activationCriteriaEn: target?.activationCriteriaEn || '',
              responsibleFloor: target?.responsibleFloor || merged.floor || '-',
              responsibleFloorList:
                target?.responsibleFloorList ||
                normalizeFloorCodes(merged.floor),
              members: nextMembers.length ? nextMembers : target?.members || [],
            }

            if (!target) return [...prev, nextTeam]

            return prev.map((team) =>
              team.id === merged.emergencyTeamId ? nextTeam : team,
            )
          })
        }

        setRecordById(merged)
      } finally {
        setRecordDetailLoading(id, false)
      }
    },
    [runDetail, setRecordById],
  )

  const resetListMode = useCallback(() => {
    resetActivationDraftState()
    setMode('list')
    setDetailRecordId(null)
    setDetailSourceTab('active')
    setStepModalVisible(false)
  }, [resetActivationDraftState])

  const backToList = useCallback(() => {
    resetListMode()
    navigate(ACTIVATION_LIST_PATH)
  }, [navigate, resetListMode])

  useEffect(() => {
    loadTeamOptions('')
  }, [loadTeamOptions])

  const enterActivateMode = useCallback(() => {
    resetActivationDraftState()
    setMode('activate')
    setScenarioRows([])

    form.resetFields()
  }, [form, resetActivationDraftState])

  const enterDetailMode = useCallback(
    async (id: string, tab: ListTab) => {
      setDetailRecordId(id)
      setDetailSourceTab(tab)
      setMode('detail')
      try {
        await loadDetailById(id)
      } catch {
        resetListMode()
        navigate(ACTIVATION_LIST_PATH, { replace: true })
      }
    },
    [loadDetailById, navigate, resetListMode],
  )

  useEffect(() => {
    if (location.pathname === ACTIVATION_CREATE_PATH) {
      enterActivateMode()
      return
    }

    if (activationId) {
      const nextSourceTab: ListTab =
        sourceTab === 'history' ? 'history' : 'active'
      void enterDetailMode(String(activationId), nextSourceTab)
      return
    }

    resetListMode()
  }, [
    activationId,
    enterActivateMode,
    enterDetailMode,
    location.pathname,
    navigate,
    resetListMode,
    sourceTab,
  ])

  const openActivateForm = useCallback(() => {
    navigate(ACTIVATION_CREATE_PATH)
  }, [navigate])

  const openDetail = useCallback(
    (id: string) => {
      navigate(getActivationDetailPath(id, listTab))
    },
    [listTab, navigate],
  )

  const openRelatedIncident = useCallback(
    (record: ActivationRecord) => {
      // TODO(联调): Incident Report 详情路由待 Incident 模块改造确定,
      // 暂跳转至 Incident Report 列表占位
      void record.relatedIncidentBizId
      navigate(INCIDENT_REPORT_DETAIL_PATH)
    },
    [navigate],
  )

  const refreshTableFromFirstPage = () => {
    tableRef.current?.setPageNum?.(DEFAULT_MIN_ID)
    tableRef.current?.refresh?.()
  }

  const handleSearchSubmit = (values: any) => {
    setKeyword(values?.keyword || '')
    refreshTableFromFirstPage()
  }

  const handleSearchReset = () => {
    setKeyword('')
    refreshTableFromFirstPage()
  }

  const getList = useCallback(
    async (params?: any) => {
      const pageNum = params?.pageNum || DEFAULT_MIN_ID
      const pageSize = params?.pageSize || DEFAULT_PAGE_SIZE

      const req = {
        pageNum,
        pageSize,
        keyword: keyword || undefined,
      }

      try {
        const api = listTab === 'active' ? runActivePage : runHistoryPage
        const res = (await api(req)) as PageRes<ActivationListItemDto>

        const list = (res?.list || []).map((item) => {
          const record = toActivationRecord(item)
          setRecordById(record)
          return record
        })

        return {
          list,
          total: Number(res?.total || DEFAULT_EMPTY_NUM),
          pageNum,
          pageSize,
        }
      } catch {
        return {
          list: [],
          total: DEFAULT_EMPTY_NUM,
          pageNum,
          pageSize,
        }
      }
    },
    [keyword, listTab, runActivePage, runHistoryPage, setRecordById],
  )

  const onEmergencyTypeChange = async (emergencyType?: number) => {
    setSelectedEmergencyType(emergencyType)
    setSelectedScenarioId(null)
    setSelectedSeverity(null)
    setSeverityOptions([])
    setSelectedTeamId(undefined)
    form.setFieldsValue({
      emergencyScenarioId: undefined,
      floor: undefined,
    })
    setSelectedFloors([])
    await loadPlanOptionsByType(emergencyType)
  }

  const onScenarioChange = async (scenarioId?: string | number) => {
    const planId =
      scenarioId === undefined || scenarioId === null || scenarioId === ''
        ? undefined
        : String(scenarioId)
    if (!planId) {
      setSelectedScenarioId(null)
      setSeverityOptions([])
      setSelectedSeverity(null)
      setSelectedTeamId(undefined)
      return
    }

    setSelectedScenarioId(planId)
    await loadSeverityOptionsByPlan(planId)
    await loadTeamForScenario(planId)
  }

  const onFloorChange = (floors?: string[]) => {
    setSelectedFloors((floors || []).map(String))
  }

  const handleConfirm = async () => {
    const values = await form.validate()

    if (!values?.emergencyScenarioId) {
      Message.warning(
        t('emergencyTeams:emergencyActivation.messages.selectScenarioFirst'),
      )
      return
    }
    if (!severityOptions.length) {
      Message.warning(
        t('emergencyTeams:emergencyActivation.messages.severityUnavailable'),
      )
      return
    }
    if (!selectedSeverity) {
      Message.warning(
        t('emergencyTeams:emergencyActivation.messages.selectSeverityFirst'),
      )
      return
    }

    const payload = {
      emergencyType: values.emergencyType,
      planId: String(values.emergencyScenarioId ?? ''),
      severityLevel: selectedSeverity,
      locationType:
        Number(values.emergencyLocation) === EMERGENCY_LOCATION.ON_SITE ? 1 : 0,
      floors: values.floor || [],
    }

    const rawId = await runAddActivation(payload)
    const activationId =
      rawId === undefined || rawId === null ? '' : String(rawId)
    Message.success(
      t('emergencyTeams:emergencyActivation.messages.activateSuccess'),
    )

    if (activationId) {
      setListTab('active')
      navigate(getActivationDetailPath(activationId, 'active'))
      return
    }

    backToList()
    tableRef.current?.refresh?.()
  }

  const handleStepCompleteSubmit = async (payload: StepCompletePayload) => {
    if (!selectedDetailRecord) return

    const activationId = selectedDetailRecord.id
    const currentStep = selectedDetailRecord.detailState.currentStep

    // Close 由后端依关联 Incident Report 状态自动触发,前端只推进至 Recovered
    await runCompleteStage({
      activationId,
      activityCode: getNextStageActivityCode(currentStep),
      durationDay: payload.durationDay,
      durationHour: payload.durationHour,
      durationMinute: payload.durationMinute,
      noteAr: toOptionalText(payload.noteAr),
      noteEn: toOptionalText(payload.noteEn),
      attachmentList: payload.attachmentList || [],
    })
    setStepModalVisible(false)
    await loadDetailById(activationId)
    tableRef.current?.refresh?.()
  }

  const columns: TableColumnProps<ActivationRecord>[] = useMemo(
    () => [
      {
        title: t('emergencyTeams:emergencyActivation.columns.responseId'),
        dataIndex: 'activationCode',
        width: 170,
        render: (value: string) => renderEllipsisText(value || '-'),
      },
      {
        title: t(
          'emergencyTeams:emergencyActivation.columns.relatedIncidentId',
        ),
        dataIndex: 'relatedIncidentCode',
        width: 180,
        render: (value: string, record) =>
          value ? (
            <Button
              type='text'
              size='mini'
              className='emergency-response-activation-page__incident-link'
              onClick={() => openRelatedIncident(record)}
            >
              {value}
            </Button>
          ) : (
            '-'
          ),
      },
      {
        title: t('emergencyTeams:emergencyResponsePlan.columns.scenarioName'),
        dataIndex: 'scenarioNameEn',
        width: 200,
        render: (_value, record) => {
          const related = handelFieldNameShow(
            record?.scenarioNameEn,
            record?.scenarioNameAr,
          )
          return renderEllipsisText(related || '-')
        },
      },
      {
        title: t('emergencyTeams:emergencyActivation.columns.emergencyType'),
        dataIndex: 'emergencyType',
        width: 190,
        render: (value: number) => emergencyTypeLabelMap[value] || '-',
      },
      {
        title: t('emergencyTeams:emergencyActivation.columns.emergencyTeam'),
        dataIndex: 'emergencyTeamId',
        width: 160,
        render: (_value: number, record) => {
          const related = handelFieldNameShow(
            record?.teamNameEn,
            record?.teamNameAr,
          )
          return renderEllipsisText(related || '-')
        },
      },
      {
        title: t('emergencyTeams:emergencyActivation.columns.severityLevel'),
        dataIndex: 'severityLevel',
        width: 130,
        render: (value: number) => (value ? `L${value}` : '-'),
      },
      {
        title: t(
          'emergencyTeams:emergencyActivation.columns.emergencyLocation',
        ),
        dataIndex: 'emergencyLocation',
        width: 170,
        render: (value: number) =>
          value === undefined || value === null
            ? '-'
            : value === EMERGENCY_LOCATION.ON_SITE
              ? t('emergencyTeams:emergencyActivation.locations.onSite')
              : t(
                  'emergencyTeams:emergencyActivation.locations.offSiteVirtual',
                ),
      },
      {
        title: t('emergencyTeams:emergencyActivation.columns.floor'),
        dataIndex: 'floor',
        width: 120,
        render: (value: string) => renderEllipsisText(value || '-'),
      },
      {
        title: t('emergencyTeams:emergencyActivation.detail.activationTime'),
        dataIndex: 'activatedTime',
        width: 180,
        render: (value: string) => renderEllipsisText(value || '-'),
      },
      {
        title: t('emergencyTeams:emergencyActivation.detail.lastUpdatedTime'),
        dataIndex: 'lastUpdatedTime',
        width: 180,
        render: (value: string) => renderEllipsisText(value || '-'),
      },
      {
        title: t('emergencyTeams:emergencyActivation.detail.emergencyStatus'),
        dataIndex: 'currentStep',
        width: 150,
        render: (value: number, record) => {
          const statusText =
            record.currentStepName || (value ? String(value) : '-')
          if (statusText === '-') return statusText

          const statusTone = getActivationStatusTone(
            value,
            record.currentStepName,
          )
          return (
            <span
              className={`emergency-response-activation-page__status emergency-response-activation-page__status--${statusTone}`}
              title={statusText}
            >
              <i className='emergency-response-activation-page__status-dot'></i>
              <span className='emergency-response-activation-page__status-text'>
                {statusText}
              </span>
            </span>
          )
        },
      },
      {
        title: t(
          'emergencyTeams:emergencyActivation.detail.responsibleEmergencyTeams',
        ),
        dataIndex: 'responsibleEmergencyTeam',
        width: 230,
        render: (value: string) => renderEllipsisText(value || '-'),
      },
      {
        title: t('emergencyTeams:emergencyActivation.detail.needEvacuation'),
        dataIndex: 'needEvacuation',
        width: 150,
        render: (value: number) => {
          if (value === 1) return t('common:yes')
          if (value === 0) return t('common:no')
          return '-'
        },
      },
      {
        title: t('common:columns.action'),
        dataIndex: 'actions',
        width: 120,
        fixed: 'right',
        render: (_value, record) => (
          <Button
            type='text'
            size='mini'
            className='emergency-response-activation-page__detail-btn'
            onClick={() => openDetail(record.id)}
          >
            <Space size={4}>
              <IconEye />
              <span>{t('common:btn.detail')}</span>
            </Space>
          </Button>
        ),
      },
    ],
    [emergencyTypeLabelMap, openDetail, openRelatedIncident, t],
  )

  const breadcrumbRoutes =
    mode === 'list'
      ? [
          {
            path: ACTIVATION_LIST_PATH,
            breadcrumbName: t('emergencyTeams:emergencyActivation.title'),
          },
        ]
      : [
          {
            path: ACTIVATION_LIST_PATH,
            breadcrumbName: t('emergencyTeams:emergencyActivation.title'),
          },
          {
            path: '#',
            breadcrumbName: t(
              'emergencyTeams:emergencyActivation.activateTitle',
            ),
          },
        ]

  if (mode === 'list') {
    return (
      <PageWrapper
        showBreadcrumb={false}
        routes={breadcrumbRoutes}
        // resetMarginTop={true}
        hseHeader={false}
        headerTitle={t('emergencyTeams:emergencyActivation.titleUpper')}
        pageClassName='emergency-response-activation-page emergency-response-activation-page--list'
      >
        <FullScreenTableSection
          enableCardStyle
          detachedFilterArea
          filterTitle={
            <div className='emergency-response-activation-page__header'>
              <div className='emergency-response-activation-page__title'>
                {t('emergencyTeams:emergencyActivation.titleUpper')}
              </div>
              <div className='emergency-response-activation-page__tabs'>
                <button
                  type='button'
                  className={`emergency-response-activation-page__tab ${
                    listTab === 'active' ? 'is-active' : ''
                  }`}
                  onClick={() => {
                    setListTab('active')
                    tableRef.current?.setPageNum?.(DEFAULT_MIN_ID)
                    tableRef.current?.refresh?.()
                  }}
                >
                  {t('emergencyTeams:emergencyActivation.tabs.active')}
                </button>
                <button
                  type='button'
                  className={`emergency-response-activation-page__tab ${
                    listTab === 'history' ? 'is-active' : ''
                  }`}
                  onClick={() => {
                    setListTab('history')
                    tableRef.current?.setPageNum?.(DEFAULT_MIN_ID)
                    tableRef.current?.refresh?.()
                  }}
                >
                  {t('emergencyTeams:emergencyActivation.tabs.history')}
                </button>
              </div>
            </div>
          }
          scrollOptions={{
            x: 'max-content',
            minY: 240,
            topGap: 8,
            paginationReserve: 100,
          }}
          filterArea={
            <ListFilterHseForm
              onSubmit={handleSearchSubmit}
              onReset={handleSearchReset}
              inputSearchParams={{
                keyword: 'keyword',
                placeholder: t(
                  'emergencyTeams:emergencyActivation.searchPlaceholder',
                ),
              }}
              renderBtnJsx={
                listTab === 'active' ? (
                  <Button
                    type='primary'
                    icon={<IconPlus />}
                    onClick={openActivateForm}
                  >
                    {t('emergencyTeams:emergencyActivation.activateButton')}
                  </Button>
                ) : null
              }
            />
          }
        >
          {() => (
            <UnifiedTableStyle
              ref={tableRef}
              rowKey='id'
              columns={columns}
              getList={getList}
              showNoColumn={false}
              loading={true}
            />
          )}
        </FullScreenTableSection>
      </PageWrapper>
    )
  }

  if (mode === 'detail' && selectedDetailRecord) {
    return (
      <>
        <PageWrapper
          showBreadcrumb
          routes={breadcrumbRoutes}
          resetMarginTop={true}
          resetPageWrapperPadding={true}
          headerTitle={t(
            'emergencyTeams:emergencyActivation.activateTitleUpper',
          )}
          pageClassName='emergency-response-activation-page emergency-response-activation-page--form'
        >
          <ActivationDetailSection
            record={selectedDetailRecord}
            team={teamMap[selectedDetailRecord.emergencyTeamId]}
            isArabic={isLanguageAR}
            t={t}
            emergencyTypeLabelMap={emergencyTypeLabelMap}
            loading={Boolean(detailLoadingMap[selectedDetailRecord.id])}
            readonly={detailSourceTab === 'history'}
            onClose={backToList}
            onStepComplete={() => setStepModalVisible(true)}
            onOpenIncident={() => openRelatedIncident(selectedDetailRecord)}
          />
        </PageWrapper>

        <StepCompleteModal
          visible={stepModalVisible}
          type={stepModalType}
          submitLoading={stageLoading}
          t={t}
          uploadRequest={uploadActivationFile}
          onCancel={() => setStepModalVisible(false)}
          onSubmit={handleStepCompleteSubmit}
        />
      </>
    )
  }

  if (mode === 'detail') {
    return (
      <PageWrapper
        showBreadcrumb
        routes={breadcrumbRoutes}
        resetMarginTop={true}
        resetPageWrapperPadding={true}
        headerTitle={t('emergencyTeams:emergencyActivation.activateTitleUpper')}
        pageClassName='emergency-response-activation-page emergency-response-activation-page--form'
      />
    )
  }

  return (
    <PageWrapper
      showBreadcrumb
      resetMarginTop={true}
      routes={breadcrumbRoutes}
      headerTitle={t('emergencyTeams:emergencyActivation.activateTitleUpper')}
      pageClassName='emergency-response-activation-page emergency-response-activation-page--form'
    >
      <ActivationFormSection
        form={form as FormInstance}
        t={t}
        isArabic={isLanguageAR}
        emergencyTypeOptions={emergencyTypeOptions}
        scenarioOptions={scenarioOptions}
        floorOptions={floorOptions}
        selectedTeam={selectedTeam}
        selectedScenario={selectedScenario}
        severityOptions={severityOptions}
        selectedSeverity={selectedSeverity}
        selectedEmergencyType={selectedEmergencyType}
        submitLoading={submitLoading}
        onEmergencyTypeChange={onEmergencyTypeChange}
        onScenarioChange={onScenarioChange}
        onFloorChange={onFloorChange}
        onSelectSeverity={setSelectedSeverity}
        onCancel={backToList}
        onConfirm={handleConfirm}
      />
    </PageWrapper>
  )
}

export default EmergencyResponseActivation

input.old_string:
render: (value: number, record) => {
  const statusText =
    record.currentStepName || (value ? String(value) : '-')
  if (statusText === '-') return statusText

  const statusTone = getActivationStatusTone(
    value,
    record.currentStepName,
  )
  return (
    <span
