import './index.less'
import { useCallback, useMemo, useRef, useState } from 'react'
import {
  Badge,
  Button,
  DatePicker,
  Form,
  Input,
  Link,
  Modal,
  Radio,
  Select,
  Space,
  Divider,
} from '@arco-design/web-react'
import type { TableColumnProps } from '@arco-design/web-react'
import {
  IconClose,
  IconEye,
  IconPen,
  IconPlus,
  IconUpload,
  IconDelete,
  IconSearch
} from '@arco-design/web-react/icon'
import ContractorHeader from '../components/ContractorHeader'
import ListFilterHseForm from '@common/components/ListFilterHseForm'
import UnifiedTableStyle from '@common/components/UnifiedTableStyle'
import { renderEllipsisText } from '@common/components/EllipsisText'
import { getLanguage } from '@common/utils/localStorage'
import { LanguageEnum } from '@common/constants/language'
import { tableHeaderCellStyle } from '@/constants/table'
import { useNavigate } from 'react-router-dom'
import { getPatrolList, savePatrol } from '@/service'
import { useRequest } from 'ahooks'

// status: 0=Draft 1=UnderReview 2=Approved 3=Rejected
// shift:  1=Day   2=Night

interface PatrolRecordRow {
  patrolId: number
  patrolDate: string
  shift: number
  patrollerUserId: number
  patrollerUser: string
  status: number
  answerCount: number
  issuesObserved: number
  inspector: string
  reportTime: string
}

interface PatrolRecordFilters {
  status?: number
  patrolDate?: { startTime?: string; endTime?: string }
  shift?: any
}

const classPrefix = 'contractor-patrol-record'

const statusColorMap: Record<number, string> = {
  0: '#86909C',
  1: '#FF7D00',
  2: '#45AD5E',
  3: '#F53F3F',
}

const statusTextMap: Record<number, string> = {
  0: 'Draft',
  1: 'Under Review',
  2: 'Approved',
  3: 'Rejected',
}

const shiftTextMap: Record<number, string> = {
  1: 'Day',
  2: 'Night',
}

interface AddPatrolFormValues {
  shift: number
  patrollerName: string
  patrolDate?: string
}

const today = new Date().toISOString().slice(0, 10)

const PatrolRecord = () => {
  const navigate = useNavigate()
  const tableRef = useRef<any>(null)
  const [filters, setFilters] = useState<PatrolRecordFilters>({})
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const [addModalVisible, setAddModalVisible] = useState(false)
  const [addForm] = Form.useForm<AddPatrolFormValues>()
  const formDataRef = useRef<AddPatrolFormValues | null>(null)

  const statusOptions = useMemo(
    () => [
      { label: 'Draft', value: 0 },
      { label: 'Under Review', value: 1 },
      { label: 'Approved', value: 2 },
      { label: 'Rejected', value: 3 },
    ],
    [],
  )

  const getList = useCallback(
    async (params?: { pageNum?: number; pageSize?: number }) => {
      const pageNum = params?.pageNum || 1
      const pageSize = params?.pageSize || 20

      const res: any = await getPatrolList({
        pageNum,
        pageSize,
        shift: filters.shift ?? undefined,
        status: filters.status ?? undefined,
        startDate: filters.patrolDate?.startTime || undefined,
        endDate: filters.patrolDate?.endTime || undefined,
      })

      const list: PatrolRecordRow[] = res?.list || []
      const total: number = res?.total || 0

      return { list, total, pageNum, pageSize }
    },
    [filters],
  )

  const handleSubmit = (values: PatrolRecordFilters) => {
    setFilters(values || {})
    tableRef.current?.setPageNum?.(1)
    tableRef.current?.refresh?.()
  }

  const handleReset = () => {
    setFilters({})
    tableRef.current?.setPageNum?.(1)
    tableRef.current?.refresh?.()
  }

  const columns: TableColumnProps<PatrolRecordRow>[] = useMemo(
    () => [
      {
        title: 'Patrol ID',
        dataIndex: 'code',
        width: 160,
        headerCellStyle: tableHeaderCellStyle,
      },
      {
        title: 'Patrol Date',
        dataIndex: 'patrolDate',
        width: 160,
        headerCellStyle: tableHeaderCellStyle,
      },
      {
        title: 'Shift',
        dataIndex: 'shift',
        width: 120,
        headerCellStyle: tableHeaderCellStyle,
        render: (value: number) => shiftTextMap[value] ?? value,
      },
      {
        title: 'Patroller',
        dataIndex: 'inspector',
        width: 120,
        headerCellStyle: tableHeaderCellStyle,
        render: (_, record) => {
          return renderEllipsisText(record?.inspector)
        },
      },
      {
        title: 'Issues',
        dataIndex: 'issuesObserved',
        width: 100,
        headerCellStyle: tableHeaderCellStyle,
      },
      {
        title: 'Status',
        dataIndex: 'status',
        width: 110,
        headerCellStyle: tableHeaderCellStyle,
        render: (value: number) => (
          <Badge
            color={statusColorMap[value] ?? '#86909C'}
            text={statusTextMap[value] ?? '-'}
          />
        ),
      },
      {
        title: 'Last Updated',
        dataIndex: 'lastUpdatedTime',
        width: 150,
        headerCellStyle: tableHeaderCellStyle,
        render: (_, record) => {
          return renderEllipsisText(record?.reportTime)
        },
      },
      {
        title: 'Actions',
        dataIndex: 'actions',
        width: 80,
        fixed: 'right',
        headerCellStyle: tableHeaderCellStyle,
        render: (_value, record) => {
          const isEditable = record.status === 0 || record.status === 3
          return (
            <div className='patrol-record-actions'>
              {
                <Link
                  icon={isEditable ? <IconPen /> : <IconEye />}
                  className='coc-table-link'
                  onClick={() =>
                    isEditable
                      ? navigate(`/contractor/addOrEdit/${record?.patrolId}`)
                      : navigate(`/contractor/detail/${record?.patrolId}`)
                  }
                ></Link>
              }
              {record.status === 0 && (
                <Divider type='vertical' className='actions-divider' />
              )}
              {record.status === 0 && (
                <Link
                  icon={<IconDelete />}
                  className='coc-table-link'
                  onClick={() => handleDelete(record?.patrolId)}
                ></Link>
              )}
            </div>
          )
        },
      },
    ],
    [isLanguageAR, navigate],
  )

  const handleDelete = (patrolId: number) => {}
  const { run: runPatrolId, loading: getPatrolIdLoading } = useRequest(
    savePatrol,
    {
      manual: true,
      onSuccess: (res: any) => {
        navigate(`/contractor/addOrEdit/${res}`, { state: formDataRef.current })
        setAddModalVisible(false)
        addForm.resetFields()
      },
    },
  )

  const addPatrol = () => {
    setAddModalVisible(true)
  }

  const handleAddConfirm = () => {
    addForm.validate().then((values) => {
      formDataRef.current = { ...values, patrolDate: today }
      const data = formDataRef.current
      runPatrolId(data)
    })
  }

  const handleAddCancel = () => {
    setAddModalVisible(false)
    addForm.resetFields()
  }
  return (
    <div className={classPrefix}>
      <ContractorHeader />
      <div className={`${classPrefix}__content`}>
        <ListFilterHseForm
          showKeywordInput={false}
          onSubmit={handleSubmit}
          onReset={handleReset}
          renderBtnJsx={
            <Button type='primary' icon={<IconPlus />} onClick={addPatrol}>
              Add Patrol Record
            </Button>
          }
        >
          <div className='search-form-box'>
            <Form.Item field='shift'>
              <Input
                allowClear
                prefix={<IconSearch />}
                placeholder={'Search Patroller'}
                style={{ width: 220 }}
              />
            </Form.Item>
            <Form.Item field='status'>
              <Select
                allowClear
                placeholder='Select Status'
                options={statusOptions}
                style={{ width: 180 }}
              />
            </Form.Item>
            <Form.Item
              field='patrolDate'
              normalize={(value) => ({
                startTime: value?.[0],
                endTime: value?.[1],
              })}
              formatter={(value) =>
                value?.startTime ? [value.startTime, value.endTime] : []
              }
            >
              <DatePicker.RangePicker
                format='YYYY-MM-DD'
                placeholder={['Date From', 'Date To']}
                style={{ width: 260 }}
              />
            </Form.Item>
          </div>
        </ListFilterHseForm>
        <div className={`${classPrefix}__table`}>
          <UnifiedTableStyle
            ref={tableRef}
            rowKey='securityPatrolId'
            columns={columns}
            getList={getList}
            showNoColumn={false}
            showPagination={true}
            border={true}
            tableHeight={40}
          />
        </div>
      </div>

      <Modal
        title='Add Patrol Record'
        visible={addModalVisible}
        onCancel={handleAddCancel}
        footer={
          <Space>
            <Button icon={<IconClose />} onClick={handleAddCancel}>
              Cancel
            </Button>
            <Button
              type='primary'
              icon={<IconUpload />}
              loading={getPatrolIdLoading}
              onClick={handleAddConfirm}
            >
              Confirm
            </Button>
          </Space>
        }
      >
        <Form form={addForm} layout='vertical' initialValues={{ shift: 1 }}>
          <Form.Item label='Patrol Date'>
            <Input value={today} disabled />
          </Form.Item>
          <Form.Item
            field='shift'
            label='Shift'
            rules={[{ required: true, message: 'Please select a shift' }]}
          >
            <Radio.Group>
              <Radio value={1}>Day</Radio>
              <Radio value={2}>Night</Radio>
            </Radio.Group>
          </Form.Item>
          <Form.Item
            field='inspector'
            label='Patroller Name'
            rules={[{ required: true, message: 'Please enter patroller name' }]}
          >
            <Input placeholder='Enter patroller name' />
          </Form.Item>
        </Form>
      </Modal>
    </div>
  )
}

export default PatrolRecord

