import { FC } from 'react'
import { IconInfoCircleFill } from '@arco-design/web-react/icon'
import ModalWindow from '../ModalWindow'

interface DeleteConfirmModalProps {
  visible: boolean
  onOk: () => void
  onCancel: () => void
  loading?: boolean
  title?: string
  content?: string
}

const DeleteConfirmModal: FC<DeleteConfirmModalProps> = ({
  visible,
  onOk,
  onCancel,
  loading,
  title = 'Delete Confirmation',
  content = 'Are you sure to delete? This action cannot be undone.',
}) => {
  return (
    <ModalWindow
      visible={visible}
      title={title}
      tipText={content}
      okText='Delete'
      cancelText='Cancel'
      setVisible={(_v, flag) => {
        if (flag === 'ok') onOk()
        else onCancel()
      }}
      okButtonProps={{ loading }}
      icon={<IconInfoCircleFill style={{ fontSize: 20, color: '#ff7d00', flexShrink: 0, alignSelf: 'flex-start' }} />}
    />
  )
}

export default DeleteConfirmModal

